  ('elementary-0c700c30-moex-00430', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '參加國家考試的阿明對於考試信心滿滿，收到考試成績單後，居然落榜！他決定提起救濟。關於阿明行 政救濟的程序，下列何者正確？', '["阿明對於成績有疑義要向辦理國家考試的考試院提申訴", "若不服訴願結果，可向地方法院行政訴訟庭提起第一審訴訟", "若阿明不服第一審訴訟結果，還可以上訴到最高行政法院", "若最高行政法院判決敗訴，阿明可以透過非常上訴尋求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00431', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '世界上多數國家從1960年代起，陸續將投票年齡從21歲下修至18歲，因應世界潮流，我國朝野也有投 票權年齡下修的共識。依據憲法增修條文規定，有關修法的程序，下列敘述何者正確？', '["人民連署提案後，逕由公民投票決定", "行政院院會提案，交由立法院表決通過", "立法院提案表決通過後，由公民複決", "立法院提案表決後，交憲法法庭審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00432', 'elementary-0c700c30', 'elementary-0c700c30-moex-112-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '我國以憲法為基礎，發展法律分類而組成法律體系，下列敘述何者正確？', '["法律位階較憲法低，有牴觸憲法疑慮時，由大法官提出聲請並解釋", "以「條例、通則」為名稱者，須經中央立法機關三讀程序制定", "行政機關發布的行政命令不具強制性，僅為人民遵循國家統治的參考", "依據法規範體系，法位階層級越高，效力越強，規定必須越明確詳盡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:32+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "508", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
